var cols = new ColumnSet("lastname", "custom_Field1");
var contact = service.Retrieve("contact", ctx.PrimaryEntityId, cols);
var updatedValue = contact.GetAttributeValue<string>("lastname");
updatedValue += contact.GetAttributeValue<string>("custom_field1");
contact["custom_field2"] = updatedValue;
service.Update(contact);
```

